 1	import { type FC, type ReactNode, useRef, useState } from 'react';
 2	
 3	import {
 4	  Drawer,
 5	  DrawerActions,
 6	  DrawerCloseButton,
 7	  DrawerContent,
 8	  DrawerContentBody,
 9	  DrawerPanelBody,
10	  DrawerPanelContent,
11	} from '@patternfly/react-core';
12	
13	import { DrawerContext } from './DrawerContext';
14	
15	import './DrawerProvider.scss';
16	
17	export const DrawerProvider: FC<{ children: ReactNode }> = ({ children }) => {
18	  const [isOpen, setIsOpen] = useState(false);
19	  const [drawerContent, setDrawerContent] = useState<ReactNode>(null);
20	  const [drawerTitle, setDrawerTitle] = useState<ReactNode>(null);
21	  const focusRef = useRef<HTMLDivElement>(null);
22	
23	  const openDrawer = (content: ReactNode, title?: ReactNode) => {
24	    setDrawerContent(content);
25	    setDrawerTitle(title ?? null);
26	    setIsOpen(true);
27	  };
28	
29	  const closeDrawer = () => {
30	    setIsOpen(false);
31	  };
32	
33	  const panelContent = (
34	    <DrawerPanelContent>
35	      <DrawerPanelBody className="pf-v6-c-drawer__head drawer-head">
36	        <span ref={focusRef} tabIndex={isOpen ? 0 : -1}>
37	          {drawerTitle}
38	        </span>
39	        <DrawerActions>
40	          <DrawerCloseButton onClick={closeDrawer} />
41	        </DrawerActions>
42	      </DrawerPanelBody>
43	      <DrawerPanelBody>{drawerContent}</DrawerPanelBody>
44	    </DrawerPanelContent>
45	  );
46	
47	  return (
48	    <DrawerContext.Provider value={{ closeDrawer, isOpen, openDrawer }}>
49	      <Drawer isExpanded={isOpen} onExpand={() => focusRef.current?.focus()} position="right">
50	        <DrawerContent panelContent={panelContent}>
51	          <DrawerContentBody>{children}</DrawerContentBody>
52	        </DrawerContent>
53	      </Drawer>
54	    </DrawerContext.Provider>
55	  );
56	};

